<?php namespace App\Services\Cache; use Illuminate\Support\Facades\Cache; use Illuminate\Support\Facades\Redis; class RedisManager { public function put(string $key, $value, int $ttl = 3600, array $tags = []): bool { if (!empty($tags)) { return Cache::tags($tags)->put($key, $value, $ttl); } return Cache::put($key, $value, $ttl); } public function get(string $key, array $tags = [], $default = null) { if (!empty($tags)) { return Cache::tags($tags)->get($key, $default); } return Cache::get($key, $default); } public function forget(string $key, array $tags = []): bool { if (!empty($tags)) { return Cache::tags($tags)->forget($key); } return Cache::forget($key); } public function flushTags(array $tags): void { Cache::tags($tags)->flush(); } public function remember(string $key, int $ttl, callable $callback, array $tags = []) { if (!empty($tags)) { return Cache::tags($tags)->remember($key, $ttl, $callback); } return Cache::remember($key, $ttl, $callback); } public function increment(string $key, int $value = 1): int { return Cache::increment($key, $value); } }